mapper.select:
SELECT w.*, c.title as competition_title, u.real_name as student_name, t.name as team_name,
       (SELECT AVG(score) FROM scoring s WHERE s.work_id = w.id) as average_score
FROM work w
LEFT JOIN competition c ON w.competition_id = c.id
LEFT JOIN user u ON w.student_id = u.id
LEFT JOIN team t ON w.team_id = t.id

    
        AND w.competition_id = #{competitionId}
    
    
        AND w.student_id = #{studentId}
    
    
        AND w.status = #{status}
    

ORDER BY w.submit_time DESC

mapper.update:
UPDATE work
title = #{title}, description = #{description}, file_url = #{fileUrl}, file_name = #{fileName}, status = #{status},
WHERE id = #{id}
